class Solution {
    public boolean canIWin(int maxChoosableInteger, int desiredTotal) {
        if ((maxChoosableInteger * (maxChoosableInteger + 1)) / 2 < desiredTotal) return false;
        int[] dp = new int[1 << maxChoosableInteger];
        return dfs(maxChoosableInteger, desiredTotal, 0, dp);
    }

    private boolean dfs(int maxChoosableInteger, int desiredTotal, int state, int[] dp) {
        if (dp[state] != 0) return dp[state] == 1;
        for (int i = 1; i <= maxChoosableInteger; i++) {
            if ((state & (1 << (i - 1))) == 0) {
                if (desiredTotal - i >= 0 && !dfs(maxChoosableInteger, desiredTotal - i, state | (1 << (i - 1)), dp)) {
                    dp[state] = 1;
                    return true;
                }
            }
        }
        dp[state] = -1;
        return false;
    }
}
